# Generated by agint:generate-lab. Edit the scenario/component for lab-specific setup.
from __future__ import annotations

import os
import shlex
import tempfile

from invoke.collection import Collection
from invoke.context import Context
from invoke.tasks import task

from tasks.e2e_framework import tool
from tasks.e2e_framework.aws.deploy import deploy
from tasks.e2e_framework.destroy import destroy as e2e_destroy

SCENARIO_NAME = "aws/kueue"
# The Kueue integration runs as the generic OpenMetrics check (config file
# openmetrics.yaml), so the live check instance is named `openmetrics`.
CHECK_NAME = "openmetrics"
CLUSTER_NAME = "eks"
CLUSTER_OUTPUT_KEY = f"dd-Cluster-{CLUSTER_NAME}"
KUBERNETES_NAMESPACE = "datadog"
# helm.NewKubernetesAgent names the node-agent DaemonSet "dda-<platform>-datadog";
# the Linux node agent (the one with the OpenMetrics check) is "dda-linux-datadog".
AGENT_DAEMONSET = "dda-linux-datadog"


def _full_stack_name(stack_name: str | None = None) -> str:
    return tool.get_stack_name(stack_name, SCENARIO_NAME)


def _missing_outputs_message() -> str:
    return (
        "create did not complete successfully; stack outputs are missing. "
        f"Expected {CLUSTER_OUTPUT_KEY} with kubeConfig. Check the create failure before running status/check/exec/ssh."
    )


def _cluster_output(outputs: dict) -> dict:
    if not outputs:
        raise RuntimeError(_missing_outputs_message())
    try:
        cluster = outputs[CLUSTER_OUTPUT_KEY]
    except KeyError as exc:
        raise RuntimeError(_missing_outputs_message()) from exc
    if not isinstance(cluster, dict) or "kubeConfig" not in cluster:
        raise RuntimeError(f"cluster output is missing kubeConfig: {CLUSTER_OUTPUT_KEY}")
    return cluster


def _write_kubeconfig_from_outputs(outputs: dict, full_stack_name: str) -> str:
    kubeconfig_content = _cluster_output(outputs)["kubeConfig"]
    kubeconfig_dir = tempfile.mkdtemp(prefix=f"kubeconfig-{full_stack_name}-")
    kubeconfig_path = os.path.join(kubeconfig_dir, "config")
    with open(kubeconfig_path, "w") as f:
        f.write(kubeconfig_content)
    os.chmod(kubeconfig_path, 0o600)
    os.environ["KUBECONFIG"] = kubeconfig_path
    return kubeconfig_path


def _write_kubeconfig(ctx: Context, stack_name: str | None = None) -> str:
    full_stack_name = _full_stack_name(stack_name)
    outputs = tool.get_stack_json_outputs(ctx, full_stack_name)
    return _write_kubeconfig_from_outputs(outputs, full_stack_name)


def _show_connection_message(ctx: Context, full_stack_name: str):
    outputs = tool.get_stack_json_outputs(ctx, full_stack_name)
    kubeconfig_path = _write_kubeconfig_from_outputs(outputs, full_stack_name)
    export_cmd = f"export KUBECONFIG={kubeconfig_path}"
    tool.info(f"kubectl configured — run the following to use it in other terminals:\n\n  {export_cmd}\n")
    print(export_cmd)


def _run_kubectl(ctx: Context, command: str, stack_name: str | None = None):
    if not command:
        raise ValueError("command is required")
    kubeconfig_path = _write_kubeconfig(ctx, stack_name)
    return ctx.run(f"kubectl --kubeconfig={shlex.quote(kubeconfig_path)} {command}")


def _run_kubectl_args(ctx: Context, args: list[str], stack_name: str | None = None):
    command = " ".join(shlex.quote(arg) for arg in args)
    return _run_kubectl(ctx, command, stack_name=stack_name)


@task
def create(
    ctx: Context,
    config_path: str | None = None,
    stack_name: str | None = None,
    pipeline_id: str | None = None,
    agent_version: str | None = None,
    debug: bool | None = False,
    agent_flavor: str | None = None,
    agent_config_path: str | None = None,
    local_package: str | None = None,
):
    """Create the Kubernetes integration lab and print an export KUBECONFIG command."""
    full_stack_name = deploy(
        ctx,
        SCENARIO_NAME,
        config_path=config_path,
        stack_name=stack_name,
        pipeline_id=pipeline_id,
        install_agent=True,
        agent_version=agent_version,
        debug=debug,
        use_fakeintake=False,
        agent_flavor=agent_flavor,
        agent_config_path=agent_config_path,
        local_package=local_package,
    )
    _show_connection_message(ctx, full_stack_name)
    return full_stack_name


@task
def destroy_lab(ctx: Context, config_path: str | None = None, stack_name: str | None = None):
    """Destroy resources owned by this integration lab."""
    return e2e_destroy(ctx, scenario_name=SCENARIO_NAME, config_path=config_path, stack=stack_name)


@task
def status(ctx: Context, stack_name: str | None = None):
    """Run Agent status through the Datadog DaemonSet using the generated kubeconfig."""
    return _run_kubectl_args(
        ctx,
        ["exec", "-n", KUBERNETES_NAMESPACE, "ds/" + AGENT_DAEMONSET, "--", "agent", "status"],
        stack_name=stack_name,
    )


@task
def check(ctx: Context, stack_name: str | None = None):
    """Run the configured Agent check through the Datadog DaemonSet."""
    return _run_kubectl_args(
        ctx,
        ["exec", "-n", KUBERNETES_NAMESPACE, "ds/" + AGENT_DAEMONSET, "--", "agent", "check", CHECK_NAME],
        stack_name=stack_name,
    )


@task(name="exec")
def exec_(ctx: Context, command: str | None = None, stack_name: str | None = None):
    """Run a kubectl command against the lab cluster, for example --command 'get pods -A'."""
    if command is None:
        raise ValueError("--command is required")
    return _run_kubectl(ctx, command, stack_name=stack_name)


@task
def ssh(ctx: Context, stack_name: str | None = None):
    """Print an export KUBECONFIG command for this Kubernetes lab."""
    _show_connection_message(ctx, _full_stack_name(stack_name))
    return None


collection = Collection("kueue")
collection.add_task(create)
collection.add_task(destroy_lab, name="destroy")
collection.add_task(status)
collection.add_task(check)
collection.add_task(exec_)
collection.add_task(ssh)
